import openai
import os
from typing import List, Dict
import re

# Secure configuration
openai.api_key = os.getenv("OPENAI_API_KEY")
SYSTEM_INSTRUCTIONS = """
You are a customer support assistant. Follow these guidelines:
1. Always respond in a helpful and professional manner
2. Keep responses concise but complete
3. If you don't know the answer, admit it
4. Never share personal information or sensitive data
5. Maintain customer privacy and security
6. Use clear and simple language
7. Avoid technical jargon unless necessary
8. Be polite and empathetic
"""

def sanitize_input(user_input: str) -> str:
    """Sanitize user input to prevent prompt injection"""
    if not isinstance(user_input, str):
        return ""
    
    # Remove potentially dangerous patterns
    dangerous_patterns = [
        r'(\b(abort|cancel|stop|terminate)\b)',  # Stop commands
        r'(\b(system|instructions|prompt|context)\b)',  # System manipulation
        r'(\b(overwrite|replace|modify|change)\b)',  # Modification attempts
        r'(\b(what are you|what are you doing|what is your purpose)\b)',  # Self-awareness queries
        r'(\b(who created you|who made you|who is your developer)\b)',  # Creator queries
    ]
    
    sanitized = user_input.strip()
    
    # Remove dangerous patterns
    for pattern in dangerous_patterns:
        sanitized = re.sub(pattern, '', sanitized, flags=re.IGNORECASE)
    
    # Limit input length
    sanitized = sanitized[:1000]
    
    return sanitized

def create_chat_message(user_input: str) -> List[Dict[str, str]]:
    """Create chat message structure with system instructions"""
    sanitized_input = sanitize_input(user_input)
    
    messages = [
        {"role": "system", "content": SYSTEM_INSTRUCTIONS},
        {"role": "user", "content": sanitized_input}
    ]
    
    return messages

def get_chatbot_response(user_input: str) -> str:
    """Get response from OpenAI chat model"""
    try:
        messages = create_chat_message(user_input)
        
        response = openai.ChatCompletion.create(
            model="gpt-3.5-turbo",
            messages=messages,
            max_tokens=500,
            temperature=0.7,
            timeout=30
        )
        
        return response.choices[0].message.content.strip()
    
    except Exception as e:
        return "Sorry, I'm having trouble processing your request. Please try again."

# Example usage
if __name__ == "__main__":
    while True:
        user_message = input("You: ")
        if user_message.lower() in ['quit', 'exit', 'bye']:
            break
        response = get_chatbot_response(user_message)
        print(f"Bot: {response}")